export const fmtSpots = (arr) => {
  let sorted = arr;
  if (_uLat && _uLon) {
    sorted = [...arr].sort((a, b) => {
      const [aLat, aLon] = a.c.split(",").map(Number);
      const [bLat, bLon] = b.c.split(",").map(Number);
      return haversine(_uLat, _uLon, aLat, aLon) - haversine(_uLat, _uLon, bLat, bLon);
    });
  }
  return sorted.map(s => {
    const [sLat, sLon] = s.c.split(",").map(Number);
    const dist = _uLat && _uLon ? ` · ${Math.round(haversine(_uLat, _uLon, sLat, sLon))} км` : "";
    return `📍 ${s.n}${dist}\n${ymaps(s.c)}`;
  }).join("\n\n");
};

export const fmtNearestShops = (n = 2) => {
  if (!_uLat || !_uLon) return "";
  const sorted = [...SHOPS].sort((a, b) =>
    haversine(_uLat, _uLon, a.lat, a.lng) - haversine(_uLat, _uLon, b.lat, b.lng)
  );
  return "\n\n🏪 Ближайшие магазины:\n" + sorted.slice(0, n).map(s => {
    const d = Math.round(haversine(_uLat, _uLon, s.lat, s.lng));
    return `• ${s.name} — ${s.city}, ${s.addr} (${d} км)`;
  }).join("\n");
};

