export const nearestFishSpot = (fish) => {
  const arr = SPOTS[fish] || SPOTS.лещ;
  if(!_uLat || !_uLon) return arr[0];
  return [...arr].sort((a,b)=>{
    const [aLa,aLo]=a.c.split(",").map(Number), [bLa,bLo]=b.c.split(",").map(Number);
    return haversine(_uLat,_uLon,aLa,aLo) - haversine(_uLat,_uLon,bLa,bLo);
  })[0];
};

