export const FISH_NAMES = ["амур","щука","лещ","карась","сазан","судак","карп","плотва","тарань","голавль","красноперка","толстолобик","чехонь","сом","окунь","жерех","берш","бычок","линь","пиленгас"];
export const detectFish = l => FISH_NAMES.find(f=>l.includes(f));

export const getBotReply = (q, weather) => {
  const l = q.toLowerCase();
  for(const intent of INTENTS){
    if(intent.t.some(t=>l.includes(t))){
      return intent.fn(l, weather);
    }
  }
  if(l.match(/привет|здрав|дарова|хай|добрый|хорош|как дела/)){
    return pick([
      `Здорово, рыбак! Готов помочь 🎣\n\nМогу рассказать про:\n• Точки ловли с координатами\n• Прогноз клёва по погоде\n• Снасти и насадки по любому виду рыбы\n• Правила и запреты\n• Ночную рыбалку, рыбалку с лодки\n\nСпрашивай — отвечу конкретно!`,
      `Привет! Я знаю все ямы и перекаты Дона 😄\n\nЧто интересует: куда поехать, что ловить, на что клюёт?`,
    ]);
  }
  if(l.match(/спасибо|благодар|отлично|класс|супер|молодец|пойду|поеду|удачи/)){
    return pick([
      `Ни хвоста ни чешуи! 🎣 Удачи на рыбалке — пусть клюёт!`,
      `Удачи! Если что — возвращайся за советом. Рыбных тебе мест! 🐟`,
    ]);
  }
  if(l.match(/где|куда|место|точк|река|водоём|водоем/)){
    return `Для точных координат напиши название рыбы — дам GPS-точки по ней.\n\nНапример: "где ловить леща" или "точки для судака"\n\n${ALL_SPOTS_TEXT}`;
  }
  if(l.match(/как|совет|помоги|объясн|расскаж|научи/)){
    return pick([
      `Уточни что именно интересует — по какой рыбе или снасти. Например:\n• "как ловить сазана на фидер"\n• "как выбрать удилище"\n• "как ловить нахлыстом"\n• "как привязать крючок"\n\nОтвечу конкретно с деталями 👍`,
      `Готов объяснить! Напиши точнее — какая рыба, снасть или техника? Знаю про всех жителей Дона и Азова 🎣`,
    ]);
  }
  if(weather){
    const month = new Date().getMonth();
    const score = calcBiteScore(weather.pressure, month, weather.wind, weather.waterTemp, weather.daily?.precipitation_probability_max?.[0]??0);
    const moon = moonPhase();
    const scoreText = score>=8?"отличный":score>=6?"хороший":score>=4?"средний":"слабый";
    const nearShops = fmtNearestShops(2);
    const spot1 = nearestFishSpot("лещ"), spot2 = nearestFishSpot("судак");
    return score>=7
      ? `Клёв сегодня ${scoreText}! 🎣\n\n${moon.ico} ${moon.tip}\nДавление ${weather.pressure} мм, вода +${weather.waterTemp}°C — рыба активна.\n\nСейчас на Дону: ${seasonFish(month)}\n\nБлижайшие точки:\n📍 ${spot1.n}\n${ymaps(spot1.c)}\n📍 ${spot2.n}\n${ymaps(spot2.c)}${nearShops}\n\nСпроси про конкретную рыбу или снасть — отвечу подробнее.`
      : `Клёв ${scoreText} (давление ${weather.pressure} мм).\n\n${moon.ico} ${moon.tip}\n\nПри нестабильной погоде лучше берёт хищник:\n📍 ${spot2.n}\n${ymaps(spot2.c)}${nearShops}\n\nСпроси конкретнее: "где ловить щуку", "какая насадка для карася", "почему не клюёт".`;
  }
  return pick([
    `Спроси меня конкретнее 🎣\n\nЯ могу:\n• Назвать ближайшие точки по любой рыбе\n• Дать прогноз клёва по погоде и луне\n• Рассказать снасти, насадки, прикормки\n• Объяснить технику — фидер, нахлыст, спиннинг, поплавок\n• Помочь выбрать удилище или катушку\n• Сказать что сейчас активно по сезону\n\nПример: "где ловить сома", "как ловить нахлыстом", "какое удилище выбрать для леща"`,
    `Уточни вопрос — отвечу конкретно!\n\nПро что могу рассказать:\n• Рыба: щука, судак, лещ, сазан, карась, сом, карп, амур, берш...\n• Снасти: фидер, спиннинг, поплавок, нахлыст, карповая\n• Выбор снастей: удилище, катушка, леска, крючки\n• Прикормка, насадки, техника проводки\n• Точки GPS, прогноз клёва, луна, запреты\n\nЧто интересует?`,
  ]);
};

export const getBotReplyCtx = (q, weather, ctx={}) => {
  const l = q.toLowerCase();
  const newCtx = {...ctx};
  const fish = detectFish(l);
  if(fish) newCtx.fish = fish;

  if(l.includes("фидер")) newCtx.lastTopic = "feeder";
  else if(l.includes("нахлыст")) newCtx.lastTopic = "fly";
  else if(l.includes("спиннинг")||l.includes("джиг")) newCtx.lastTopic = "spin";
  else if(l.includes("поплавоч")||l.match(/на поплавок|поплавком/)) newCtx.lastTopic = "float";
  else if(l.includes("карповая")||l.includes("бойл")) newCtx.lastTopic = "carp";
  else if(fish) newCtx.lastTopic = "fish_"+fish;

  if(l.match(/ты сам|ты рыбак|ты ловишь|ты кто|кто ты|ты умеешь|ты реальный/)) {
    return {text: pick([
      `Я — Егерь ИИ, цифровой знаток всех ям и перекатов Дона 😄 Сам физически не ловлю, но знаю про рыбалку в Ростовской области, кажется, всё что только можно. Задавай любой вопрос!`,
      `Виртуальный рыбак, но с реальными знаниями 🎣 Каждую яму, каждый перекат, каждый сезонный выход рыбы — знаю. Спрашивай смело!`,
    ]), ctx: newCtx};
  }

  if(l.match(/ещё расскажи|расскажи ещё|что ещё|хочу ещё|продолжай|подробнее расскажи|хочу знать больше|дальше/)) {
    if(newCtx.lastTopic === "feeder") return {text: getBotReply("фидер оснастка как вязать монтаж", weather), ctx: newCtx};
    if(newCtx.lastTopic === "fly")    return {text: getBotReply("нахлыст мушки на что ловить", weather), ctx: newCtx};
    if(newCtx.lastTopic === "spin")   return {text: getBotReply("спиннинг проводка как вести", weather), ctx: newCtx};
    if(newCtx.lastTopic === "float")  return {text: getBotReply("поплавочная поплавок", weather), ctx: newCtx};
    if(newCtx.lastTopic === "carp")   return {text: getBotReply("бойл карповая оснастка", weather), ctx: newCtx};
    if(newCtx.fish) return {text: getBotReply(`насадки для ${newCtx.fish}`, weather), ctx: newCtx};
    return {text: pick([
      `Уточни тему — расскажу подробнее! Про снасти, рыбу, место или технику?`,
      `Конечно! Про что конкретно — снасти, точки, насадки, технику проводки или сезон?`,
    ]), ctx: newCtx};
  }

  if(l.match(/^(понял|ясно|окей|ок|хорошо|понятно|чётко|четко|ясно стало|всё понял|все понял|принял|принято)\.?!?$/)) {
    return {text: pick([
      `Отлично! Ещё вопросы — всегда готов 🎣 Куда едешь кстати, уже решил?`,
      `Понял — молодец! Можешь спросить про снасти, точки или прогноз — отвечу быстро.`,
      `Окей! Удачи на рыбалке 🐟 Если что-то непонятно — возвращайся.`,
    ]), ctx: newCtx};
  }

  if(l.match(/отлично|здорово|круто|класс|супер|огонь|кайф|спасибо|благодар|молодец|👍/)) {
    return {text: pick([
      `Рад помочь! 🎣 Ни хвоста ни чешуи! Если ещё вопросы будут — возвращайся.`,
      `Спасибо! 😄 Удачи на рыбалке — пусть трещит удилище и гнётся удочка!`,
      `Пожалуйста! Кстати — не забудь потом отписаться что поймал 😄🐟`,
    ]), ctx: newCtx};
  }

  if(l.match(/не помог|не знаешь|не умеешь|плохой бот|бесполезн|фигня|отстой/)) {
    return {text: pick([
      `Понял тебя — постараюсь лучше! Задай вопрос конкретнее — про какую рыбу, снасть или место — отвечу точнее 🎣`,
      `Ок, попробую иначе 😄 Напиши что именно нужно — дам максимально конкретный ответ.`,
    ]), ctx: newCtx};
  }

  if(ctx.pending === 'fish') {
    if(fish) {
      newCtx.pending = null;
      const pf = ctx.pendingFor;
      if(pf === 'spots') {
        const s = nearestFishSpot(fish);
        return {text:`Точки для ловли ${fish}а:\n\n📍 ${s.n}\n${ymaps(s.c)}\n\nЕщё — спроси "ещё точки для ${fish}а"`, ctx:newCtx};
      }
      if(pf === 'bait')   return {text:getBotReply(`насадки для ${fish}`, weather), ctx:newCtx};
      if(pf === 'tackle') return {text:getBotReply(`снасти для ${fish}`, weather),  ctx:newCtx};
      newCtx.pending = 'topic';
      const cap = fish.charAt(0).toUpperCase()+fish.slice(1);
      return {text:`${cap} — отличный выбор! Что интересует:\n\n1️⃣ Точки ловли (GPS)\n2️⃣ Насадки и прикормка\n3️⃣ Снасти и оснастка\n4️⃣ Лучшее время\n\nНапиши цифру или своими словами.`, ctx:newCtx};
    }
    return {text:`Не расслышал 😄 Какую рыбу ловишь? Например: лещ, судак, щука, сазан, сом, берш, амур...`, ctx:newCtx};
  }

  if(ctx.pending === 'topic' && ctx.fish) {
    const f = ctx.fish;
    newCtx.pending = null;
    if(l.match(/^1$|точк|место|куда|где|координат/))               { const s=nearestFishSpot(f); return {text:`📍 Точки для ${f}а:\n\n${s.n}\n${ymaps(s.c)}\n\nЧто ещё интересует по ${f}у?`, ctx:newCtx}; }
    if(l.match(/^2$|насад|прикорм|наживк|мотыл|червь|опарыш|бойл/)) return {text:getBotReply(`насадки для ${f}`, weather), ctx:newCtx};
    if(l.match(/^3$|снаст|фидер|спиннинг|поплавок|удоч|оснастк/))  return {text:getBotReply(`снасти для ${f}`, weather),  ctx:newCtx};
    if(l.match(/^4$|время|сезон|когда|лучш/)) {
      const moon=moonPhase(), month=new Date().getMonth();
      return {text:`🕐 Лучшее время для ${f}а:\n\n${moon.ico} ${moon.tip}\n\nАктивен сейчас: ${seasonFish(month)}\n\nЛучшие часы: 4–8 утра и 17–20 вечера.`, ctx:newCtx};
    }
  }

  if(!fish && l.match(/где|куда|точк|место|координат/) && !l.match(/насадк|снасти?|прикорм|наживк/)) {
    if(newCtx.fish) {
      const s = nearestFishSpot(newCtx.fish);
      return {text:`Точки для ${newCtx.fish}а:\n\n📍 ${s.n}\n${ymaps(s.c)}`, ctx:newCtx};
    }
    newCtx.pending='fish'; newCtx.pendingFor='spots';
    return {text:`Какую рыбу ловишь? Дам GPS-точки именно под неё.\n\nЕсть места для: леща, судака, щуки, сазана, карася, сома, берша, амура, бычка...`, ctx:newCtx};
  }

  if(!fish && l.match(/на что|насадк|наживк|приманк/)) {
    if(newCtx.fish) return {text:getBotReply(`насадки для ${newCtx.fish}`, weather), ctx:newCtx};
    newCtx.pending='fish'; newCtx.pendingFor='bait';
    return {text:`На кого ловишь? Подберу насадку точно под рыбу.`, ctx:newCtx};
  }

  if(!fish && l.match(/снасти?|снасть|оснастк/) && !l.match(/фидер|спиннинг|поплавок/)) {
    if(newCtx.fish) return {text:getBotReply(`снасти для ${newCtx.fish}`, weather), ctx:newCtx};
    newCtx.pending='fish'; newCtx.pendingFor='tackle';
    return {text:`Снасти под какую рыбу? Укажи — дам конкретные рекомендации.`, ctx:newCtx};
  }

  if(l.match(/привет|здрав|дарова|хай|добрый|как дела/)) {
    const txt = newCtx.fish
      ? `Снова привет! Продолжаем по ${newCtx.fish}у или что-то новое? 🎣`
      : pick([`Здорово, рыбак! 🎣 Что интересует — куда поехать, что ловить, на что клюёт?`,`Привет! Спрашивай — знаю все ямы Дона 😄`]);
    return {text:txt, ctx:newCtx};
  }

  newCtx.pending = null;
  return {text:getBotReply(q, weather), ctx:newCtx};
};

export async function checkAndAwardBadges(userId, allRecords) {
  if (!userId || !allRecords.length) return;
  try {
    const total = allRecords.length;
    const withPhoto = allRecords.filter(r=>r.photoUrls&&r.photoUrls.length>0).length;
    const maxW = Math.max(...allRecords.map(r=>r.weightGrams||0),0);
    const fishSet = new Set(allRecords.map(r=>r.fishType).filter(Boolean));
    const pubCount = allRecords.filter(r=>r.isPublic).length;
    const locSet = new Set(allRecords.map(r=>r.locationName).filter(Boolean));
    const earlyBird = allRecords.filter(r=>{ const d=r.createdAt?.toDate?.(); return d&&d.getHours()<6; }).length;
    const ago30 = Date.now()-30*24*60*60*1000;
    const recentDays = new Set(allRecords.filter(r=>r.createdAt?.toDate?.()&&r.createdAt.toDate().getTime()>ago30).map(r=>r.createdAt.toDate().toDateString())).size;
    const checks=[
      {id:"first_catch",   met:total>=1},
      {id:"photographer",  met:withPhoto>=10},
      {id:"trophy_5kg",    met:maxW>=5000},
      {id:"whale_15kg",    met:maxW>=15000},
      {id:"weekly_angler", met:recentDays>=7},
      {id:"early_bird",    met:earlyBird>=3},
      {id:"traveler",      met:locSet.size>=5},
      {id:"diversity_10",  met:fishSet.size>=10},
      {id:"reporter",      met:pubCount>=10},
    ];
    const existing = await getDocs(collection(db,"users",userId,"badges"));
    const existingIds = new Set(existing.docs.map(d=>d.id));
    for (const {id,met} of checks) {
      if (met && !existingIds.has(id)) {
        await setDoc(doc(db,"users",userId,"badges",id),{badgeId:id,unlockedAt:serverTimestamp()});
        const bd = BADGE_DEFS.find(b=>b.id===id);
        logEvent("badge_unlocked",{badge_id:id});
        if (bd && "Notification" in window && Notification.permission==="granted") {
          new Notification(`${bd.emoji} Новый значок: ${bd.name}`,{body:bd.desc,icon:"https://eger-ai.app/icons/icon-192.png"});
        }
      }
    }
  } catch(e){ console.log("badges err",e); }
}
